selector_to_html = {"a[href=\"Python.html#py-play-emoji\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.19 </span>Emoji (expression) control<a class=\"headerlink\" href=\"#py-play-emoji\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_emoji</strong>, which enables the robot to display a specified expression. Users can select expressions from the available list. For the full expression list, refer to the <a class=\"reference internal\" href=\"../Interface/interactor/screen.html#tbl-emotion-id\"><span class=\"std std-ref\">expression list</span></a></p>", "a[href=\"Python.html#py-echo-cameras\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.12 </span>Camera stream examples<a class=\"headerlink\" href=\"#py-echo-cameras\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example collection provides multiple camera subscription and processing demos, supporting depth, stereo, and mono camera streams.</strong><br/>\nThese camera subscription examples are not application-level; they only print basic camera data. If you are familiar with ROS2, you can achieve similar results with <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">echo</span></code> + <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">hz</span></code>. You can consult the SDK topic list to jump directly into module development or use these camera examples as scaffolding for your own logic. <strong>The published sensor data are raw (no preprocessing like undistortion). For detailed sensor information (e.g., resolution, focal length), check the corresponding camera_info topic.</strong></p>", "a[href=\"Python.html#py-motocontrol\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.9 </span>Joint motor control<a class=\"headerlink\" href=\"#py-motocontrol\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example demonstrates how to use ROS2 and the Ruckig library to control robot joint motion.</strong></p>", "a[href=\"Python.html#py-echo-head-touch-sensor\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.13 </span>Head touch sensor data subscription<a class=\"headerlink\" href=\"#py-echo-head-touch-sensor\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_head_touch_sensor</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/touch_head</span></code> topic to receive the robot\u2019s touch sensor data on the head.</p><p><strong>Features:</strong></p>", "a[href=\"Cpp.html#cpp-echo-lidar-data\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.14 </span>LiDAR Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-lidar-data\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_lidar_data</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/lidar_chest_front/</span></code> topic to receive LiDAR data, supporting both point cloud data and IMU data types.</p><p><strong>Features:</strong></p>", "a[href=\"Python.html#py-locomotion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.8 </span>Control robot locomotion<a class=\"headerlink\" href=\"#py-locomotion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">mc_locomotion_velocity</span></code>. The example below controls robot walking by publishing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/mc/locomotion/velocity</span></code> topic. For versions after v0.7, you must register an input source before enabling velocity control (this example already registers an input source); see the code for registration steps.</strong></p><p>Start the node after switching to Stable Standing Mode:</p>", "a[href=\"Cpp.html#cpp-motocontrol\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.9 </span>Joint Motor Control<a class=\"headerlink\" href=\"#cpp-motocontrol\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example demonstrates how to use ROS2 and the Ruckig library to control the robot\u2019s joint movements.</strong></p>", "a[href=\"Python.html#py-take-photo\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.11 </span>Take photo<a class=\"headerlink\" href=\"#py-take-photo\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">take_photo</span></code>. Before running the node, set the camera topic to capture. When started, the node creates an <code class=\"docutils literal notranslate\"><span class=\"pre\">/images/</span></code> directory and saves the current frame into that directory.</strong></p>", "a[href=\"Cpp.html#cpp-play-lights\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.20 </span>LED Strip Control<a class=\"headerlink\" href=\"#cpp-play-lights\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Function Description</strong>: Demonstrates how to control the robot\u2019s LED strip, supporting multiple display modes and customizable colors.</p><p><strong>Core Code</strong>:</p>", "a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6 </span><i class=\"fa fa-code\"></i> Example Code<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"Cpp.html#cpp-play-media\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.16 </span>Media File Playback<a class=\"headerlink\" href=\"#cpp-play-media\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_media</strong>, enabling playback of specified media files (such as audio files). It supports audio formats including WAV and MP3.</p><p><strong>Features:</strong></p>", "a[href=\"Python.html#py-mic-receiver\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.18 </span>Microphone data reception<a class=\"headerlink\" href=\"#py-mic-receiver\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses mic_receiver</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/agent/process_audio_output</span></code> topic to receive noise-reduced audio data from the robot, supporting both internal and external microphone audio streams, and automatically saving complete speech segments as PCM files based on VAD (Voice Activity Detection) status.</p><p><strong>Features:</strong></p>", "a[href=\"Cpp.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2 </span>C++ Interface Usage Example<a class=\"headerlink\" href=\"#c\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This section will guide you through implementing the functions listed in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"Cpp.html#cpp-keyboard\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.10 </span>Keyboard Control of the Robot<a class=\"headerlink\" href=\"#cpp-keyboard\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example enables controlling the robot\u2019s forward, backward, and turning movements using PC keyboard input.</strong></p><p><strong>Use <kbd class=\"kbd docutils literal notranslate\">W</kbd> <kbd class=\"kbd docutils literal notranslate\">A</kbd> <kbd class=\"kbd docutils literal notranslate\">S</kbd> <kbd class=\"kbd docutils literal notranslate\">D</kbd> to control the walking direction, increase/decrease linear velocity (\u00b10.2 m/s), use <kbd class=\"kbd docutils literal notranslate\">Q</kbd> / <kbd class=\"kbd docutils literal notranslate\">E</kbd> to increase/decrease angular velocity (\u00b10.1 rad/s), <kbd class=\"kbd docutils literal notranslate\">ESC</kbd> exits the program and releases terminal resources, and <font style=\"color: red\"><kbd class=\"kbd docutils literal notranslate\">Space</kbd> immediately resets the velocity to zero to perform an emergency stop</font>.</strong></p>", "a[href=\"Python.html#py-play-video\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.15 </span>Play video<a class=\"headerlink\" href=\"#py-play-video\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_video</strong>. Before running the node, you must upload the video to the robot\u2019s <strong>Interaction Computing Unit (PC3)</strong> (you may create a directory on it to store videos, e.g. /var/tmp/videos/), and then change the <code class=\"docutils literal notranslate\"><span class=\"pre\">video_path</span></code> in the node program to the path of the video you want to play.</p>", "a[href=\"Python.html#py-keyboard\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.10 </span>Keyboard control<a class=\"headerlink\" href=\"#py-keyboard\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example implements robot forward/backward and turning control using keyboard input from a PC.</strong></p><p><strong>Use <kbd class=\"kbd docutils literal notranslate\">W</kbd> <kbd class=\"kbd docutils literal notranslate\">A</kbd> <kbd class=\"kbd docutils literal notranslate\">S</kbd> <kbd class=\"kbd docutils literal notranslate\">D</kbd> to control robot direction; increase/decrease speed by \u00b10.2 m/s. Use <kbd class=\"kbd docutils literal notranslate\">Q</kbd>/<kbd class=\"kbd docutils literal notranslate\">E</kbd> to increase/decrease angular speed by \u00b10.1 rad/s. Press <kbd class=\"kbd docutils literal notranslate\">ESC</kbd> to exit and release terminal resources. <font style=\"color: red\">Press <kbd class=\"kbd docutils literal notranslate\">Space</kbd> to immediately zero speed (emergency stop)</font>.</strong></p>", "a[href=\"Python.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1 </span>Python interface usage example<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This chapter will guide you through implementing several features shown in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"Python.html#py-set-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.2 </span>Set robot mode<a class=\"headerlink\" href=\"#py-set-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the SetMcAction service.</strong> After running the node, enter the corresponding field value of the mode in the terminal, and the robot will immediately switch to the appropriate <a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">motion mode</span></a>.<br/>\n<strong>Before switching to the Stable Standing mode (<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>), ensure the robot is standing and its feet are already on the ground.</strong><br/>\n<strong>The motion mode switching must follow its state transition digram, other transitions would be rejected</strong><br/>\n<strong>Locomotion Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code>) and Stable Standing Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>) are unified and will auto switch internally, so switching manually to the nearer one is enough</strong></p>", "a[href=\"Python.html#py-omnihand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.5 </span>Dexterous Hand Control<a class=\"headerlink\" href=\"#py-omnihand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">omnihand_control</span></code>. Publish messages to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code> topic to control the omnihand.</strong></p>", "a[href=\"Python.html#py-set-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.6 </span>Register custom input source<a class=\"headerlink\" href=\"#py-set-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>For versions after v0.7, you must register an input source before controlling the MC. This example registers a custom input source via the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aimdk_5Fmsgs/srv/SetMcInputSource</span></code> service so MC becomes aware of it; only registered input sources can perform robot velocity control.</strong></p>", "a[href=\"Cpp.html#cpp-echo-cameras\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.12 </span>Camera Streaming Example Collection<a class=\"headerlink\" href=\"#cpp-echo-cameras\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example set provides multiple camera data subscription and processing functions, supporting data streams from depth cameras, stereo cameras, and monocular cameras.</strong><br/>\nThese camera subscription examples do not provide actual application-level logic; they only print basic camera data information. If you are familiar with ROS2, you may notice that <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">echo</span></code> + <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">hz</span></code> can also achieve similar functionality. You may directly check the topic list in the SDK interface manual to start developing your own module, or you may use these camera examples as scaffolding to integrate your own business logic.  <strong>All published sensor data is raw and unprocessed (e.g., without undistortion). If you need detailed sensor information (such as resolution, focal length, etc.), please refer to the <code class=\"docutils literal notranslate\"><span class=\"pre\">camera_info</span></code> topic.</strong></p>", "a[href=\"Cpp.html#cpp-take-photo\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.11 </span>Take Photo<a class=\"headerlink\" href=\"#cpp-take-photo\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses take_photo.</strong> Before running the node, modify the camera topic from which to capture the image. After starting the node, an <code class=\"docutils literal notranslate\"><span class=\"pre\">/images/</span></code> directory will be created, and the current frame will be saved into this directory.</p>", "a[href=\"Cpp.html#cpp-get-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.7 </span>Get Current Input Source<a class=\"headerlink\" href=\"#cpp-get-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the GetCurrentInputSource service</strong>, which is used to obtain information about the currently registered input source, including the input source name, priority, and timeout settings.</p>", "a[href=\"Python.html#py-preset-motion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.3 </span>Set robot action<a class=\"headerlink\" href=\"#py-preset-motion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">preset_motion_client</span></code></strong>; after switching to Stable Stand Mode and starting the node, enter the corresponding field values to perform preset actions with the left (or right) hand such as handshake, raise hand, wave, or air kiss.</p><p>Available parameters are listed in the <a class=\"reference internal\" href=\"../Interface/control_mod/preset_motion.html#tbl-preset-motion\"><span class=\"std std-ref\">preset motions table</span></a></p>", "a[href=\"Cpp.html#cpp-get-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.1 </span>Get Robot Mode<a class=\"headerlink\" href=\"#cpp-get-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p>Retrieve the robot\u2019s current operating mode by calling the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetMcAction</span></code> service, including the description, and status information.</p><p><a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">Motion Mode Definitions</span></a></p>", "a[href=\"Python.html#py-get-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.7 </span>Get current input source<a class=\"headerlink\" href=\"#py-get-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetCurrentInputSource</span></code> service</strong> to retrieve information about the currently registered input source, including name, priority, and timeout.</p>", "a[href=\"Python.html#py-play-tts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.17 </span>TTS (Text-to-Speech)<a class=\"headerlink\" href=\"#py-play-tts\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_tts</strong>, which enables the robot to speak the provided text through the node. Users can input different text according to various scenarios.</p><p><strong>Features:</strong></p>", "a[href=\"Python.html#py-play-media\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.16 </span>Media file playback<a class=\"headerlink\" href=\"#py-play-media\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_media</strong>, which enables playback of specified media files (such as audio files) through the node, supporting audio formats including WAV and MP3.</p><p><strong>Features:</strong></p>", "a[href=\"Python.html#py-get-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.1 </span>Get robot mode<a class=\"headerlink\" href=\"#py-get-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p>Retrieve the robot\u2019s current operating mode by calling the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetMcAction</span></code> service, including the description, and status information.</p><p><a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">Motion Mode Definitions</span></a></p>", "a[href=\"Cpp.html#cpp-locomotion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.8 </span>Robot Locomotion Control<a class=\"headerlink\" href=\"#cpp-locomotion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses mc_locomotion_velocity. The following example controls the robot\u2019s walking by publishing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/mc/locomotion/velocity</span></code> topic. For versions after v0.7, an input source must be registered before enabling velocity control (this example already includes input source registration). Refer to the code for detailed registration steps.</strong></p><p>Start the node after switching to Stable Standing Mode:</p>", "a[href=\"Python.html#py-play-lights\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.20 </span>LED light strip control<a class=\"headerlink\" href=\"#py-play-lights\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Function description</strong>: Demonstrates how to control the robot\u2019s LED light strip, supporting multiple display modes and custom colors.</p><p><strong>Core code:</strong></p>", "a[href=\"Cpp.html#cpp-hand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.4 </span>Gripper Control<a class=\"headerlink\" href=\"#cpp-hand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses hand_control. By publishing messages to the topic <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code>, you can control the movement of the gripper.</strong></p>", "a[href=\"Python.html#py-echo-lidar-data\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.14 </span>LiDAR data subscription<a class=\"headerlink\" href=\"#py-echo-lidar-data\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_lidar_data</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/lidar_chest_front/</span></code> topic to receive the robot\u2019s LiDAR data, supporting both point cloud and IMU data types.</p><p><strong>Features:</strong></p>", "a[href=\"Cpp.html#cpp-play-tts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.17 </span>TTS (Text-to-Speech)<a class=\"headerlink\" href=\"#cpp-play-tts\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_tts</strong>, enabling the robot to speak the provided text. Users can input any text depending on the scenario.</p><p><strong>Features:</strong></p>", "a[href=\"Cpp.html#cpp-set-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.6 </span>Register Secondary Development Input Source<a class=\"headerlink\" href=\"#cpp-set-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>For versions after v0.7, an input source must be registered before controlling the MC. In this example, the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aimdk_5Fmsgs/srv/SetMcInputSource</span></code> service is used to register the secondary development input source, so that the MC can recognize it. Only after registration can robot velocity control be performed.</strong></p>", "a[href=\"Cpp.html#cpp-mic-receiver\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.18 </span>Microphone Audio Reception<a class=\"headerlink\" href=\"#cpp-mic-receiver\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses mic_receiver</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/agent/process_audio_output</span></code> topic to receive the robot\u2019s noise-reduced audio stream. It supports both internal and external microphone audio streams, and automatically saves complete speech segments as PCM files based on VAD (Voice Activity Detection) states.</p><p><strong>Features:</strong></p>", "a[href=\"Cpp.html#cpp-play-emoji\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.19 </span>Emoji Control<a class=\"headerlink\" href=\"#cpp-play-emoji\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_emoji</strong>, which allows the robot to display a specified emoji. Users can choose an emoji from the available list; see the <a class=\"reference internal\" href=\"../Interface/interactor/screen.html#tbl-emotion-id\"><span class=\"std std-ref\">Emoji List</span></a> for details.</p>", "a[href=\"Cpp.html#cpp-omnihand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.5 </span>Dexterous Hand Control<a class=\"headerlink\" href=\"#cpp-omnihand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses omnihand_control. By publishing messages to the topic <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code>, you can control the movement of the omnihand.</strong></p>", "a[href=\"Cpp.html#cpp-play-video\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.15 </span>Play Video<a class=\"headerlink\" href=\"#cpp-play-video\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_video.</strong> Before running the node, you must upload the video file to the robot\u2019s <strong>Interaction Computing Unit (PC3)</strong> (you may create a directory there to store videos, e.g. /var/tmp/videos/). Then, modify the <code class=\"docutils literal notranslate\"><span class=\"pre\">video_path</span></code> in the node program to the path of the video you want to play.</p>", "a[href=\"Python.html#py-hand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.4 </span>Gripper control<a class=\"headerlink\" href=\"#py-hand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">hand_control</span></code>. Publish messages to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code> topic to control the gripper.</strong></p>", "a[href=\"Cpp.html#cpp-set-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.2 </span>Set Robot Mode<a class=\"headerlink\" href=\"#cpp-set-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the SetMcAction service.</strong> After running the node, enter the corresponding field value of the mode in the terminal, and the robot will immediately switch to the appropriate <a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">motion mode</span></a>.<br/>\n<strong>Before switching to the Stable Standing mode (<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>), ensure the robot is standing and its feet are already on the ground.</strong><br/>\n<strong>The motion mode switching must follow its state transition digram, other transitions would be rejected</strong><br/>\n<strong>Locomotion Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code>) and Stable Standing Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>) are unified and will auto switch internally, so switching manually to the nearer one is enough</strong></p>", "a[href=\"Cpp.html#cpp-echo-head-touch-sensor\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.13 </span>Head touch sensor data subscription<a class=\"headerlink\" href=\"#cpp-echo-head-touch-sensor\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_head_touch_sensor</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/touch_head</span></code> topic to receive the robot\u2019s touch sensor data on the head.</p><p><strong>Features:</strong></p>", "a[href=\"Cpp.html#cpp-preset-motion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.3 </span>Set Robot Motion<a class=\"headerlink\" href=\"#cpp-preset-motion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">preset_motion_client</span></code></strong>; after switching to Stable Stand Mode and starting the node, enter the corresponding field values to perform preset actions with the left (or right) hand such as handshake, raise hand, wave, or air kiss.</p><p>Available parameters can be found in the <a class=\"reference internal\" href=\"../Interface/control_mod/preset_motion.html#tbl-preset-motion\"><span class=\"std std-ref\">Preset Motion Table</span></a></p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
